const item = $input.first().json || {};
const exec = item.execution || {};
const wf = item.workflow || {};
const err = exec.error || {};

const trim = (s, n) => !s ? '' : (String(s).length > n ? String(s).slice(0, n) + '...' : String(s));

const lines = [
  'Workflow failed',
  '',
  'Workflow: ' + (wf.name || wf.id || '(unknown)'),
  'Failing node: ' + (err.node?.name || exec.lastNodeExecuted || '(unknown)'),
  'Error: ' + trim(err.message || err.name || JSON.stringify(err), 500),
  'Execution: ' + (exec.id || '(n/a)'),
  'Mode: ' + (exec.mode || '(n/a)'),
];

// Local logs link, the cloudflared tunnel only routes /webhook/* so the
// previously-used tunnel URL did not resolve. Owner reads this DM on the
// host machine, so localhost is the right target.
if (exec.id && wf.id) {
  lines.push('', 'Logs: http://localhost:5678/workflow/' + wf.id + '/executions/' + exec.id);
}

return [{ json: { text: lines.join('\n') } }];
